import numpy as np

def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """
    Select an MCS index for the next transmission.
    """
    from utils import get_bler, bler_2_mcs

    if len(is_nack_hist) == 0:
        return 0

    def consistency_score(sinr_candidate):
        score = 0
        window_size = min(len(is_nack_hist), 15)
        start_idx = len(is_nack_hist) - window_size

        # Get BLER for all MCS at this candidate SINR once
        bler_array = get_bler(np.array([sinr_candidate]))
        if len(bler_array) == 0:
            bler_array = np.array([1.0])
        else:
            bler_array = bler_array.flatten()

        for i in range(start_idx, len(is_nack_hist)):
            mcs_val = mcs_ackned_hist[i]
            nack_val = is_nack_hist[i]

            if mcs_val < len(bler_array):
                p_nack = bler_array[int(mcs_val)]
            else:
                p_nack = 1.0

            # Log-likelihood
            if nack_val == 1:
                score += np.log(p_nack + 1e-9)
            else:
                score += np.log(1 - p_nack + 1e-9)
        return score

    # Grid search for the best SINR
    best_sinr = 10.0
    best_score = -float('inf')
    # Wider range and finer grid
    for s in np.linspace(-15, 35, 51):
        score = consistency_score(s)
        if score > best_score:
            best_score = score
            best_sinr = s

    # Use the estimated SINR to select the MCS
    bler_array = get_bler(np.array([best_sinr]))
    if len(bler_array) == 0:
        bler_array = np.array([1.0])
    else:
        bler_array = bler_array.flatten()

    mcs = bler_2_mcs(bler_array, bler_target)

    return int(mcs)

