import numpy as np
from utils import get_bler, bler_2_mcs

def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """Select an MCS index for the next transmission using a Conservative-First search strategy.

    Approach:
    Implement a 'Step-Down' approach: start from the last successful MCS and increment 
    upwards until a NACK is observed, then immediately drop the MCS by 2 levels 
    and apply a temporary safety margin.
    """

    # 1. Handle initial case
    if len(is_nack_hist) == 0:
        return 10

    # 2. Identify the last successful MCS and the last outcome
    last_nack = is_nack_hist[-1] == 1
    successful_indices = np.where(is_nack_hist == 0)[0]

    if len(successful_indices) == 0:
        if len(mcs_ackned_hist) > 0:
            return int(max(0, mcs_ackned_hist[-1] - 3))
        return 0

    last_success_idx = successful_indices[-1]
    last_success_mcs = mcs_ackned_hist[last_success_idx]

    # 3. Implement the 'Step-Down' / 'Cautious Exploration' logic

    # If the last transmission was a NACK:
    if last_nack:
        # "immediately drop the MCS by 2 levels and apply a temporary safety margin"
        # We drop 2 levels from the last success.
        new_mcs = last_success_mcs - 2
        return int(max(0, min(25, new_mcs)))

    else:
        # The last transmission was an ACK.
        # Check recent performance to decide how aggressive to be.
        recent_window = 15
        recent_nacks = np.mean(is_nack_hist[-recent_window:])

        # If we are exceeding the target BLER, we should NOT increment.
        # We should stay at the last successful MCS or even drop.
        if recent_nacks > bler_target:
            # If we are significantly over the target, drop more aggressively
            if recent_nacks > bler_target * 1.5:
                return int(max(0, min(25, last_success_mcs - 1)))
            else:
                return int(max(0, min(25, last_success_mcs)))

        # If we are performing well, we try to increment.
        # To follow the "start from last successful and increment upwards"
        # we try last_success_mcs + 1.
        new_mcs = last_success_mcs + 1

        # But let's use the helper to be more precise if we can estimate SINR.
        # Actually, the assigned approach is a heuristic. Let's stick to it.
        # Let's try to be a bit more aggressive if we are very safe.
        if recent_nacks < bler_target * 0.3:
            # Very safe, maybe try +2? No, the instruction says "increment upwards".
            # Let's stick to +1 to be safe and follow instructions.
            return int(max(0, min(25, new_mcs)))
        else:
            return int(max(0, min(25, new_mcs)))
